using UnityEngine;
using UnityEngine.UI;
using System.Collections;

public class PlatformerChallenge : MonoBehaviour
{
    // ----- Player -----
    public GameObject playerPrefab;
    public Transform spawnPoint;
    public float moveSpeed = 5f;
    public float jumpForce = 10f;

    // ----- UI -----
    public Text scoreText;
    public Text coinText;
    public Image healthBar;
    public GameObject gameOverUI;
    public GameObject winUI;

    // ----- Game State -----
    private int score = 0;
    private int coinCount = 0;
    private int maxHealth = 100;
    private int currentHealth = 100;
    private bool isGameOver = false;
    private bool hasWon = false;

    // ----- Components -----
    private Rigidbody2D rb;
    private Animator animator;
    private bool isGrounded = false;

    void Start()
    {
        // Get components
        rb = GetComponent<Rigidbody2D>();
        animator = GetComponent<Animator>();

        if (rb == null || animator == null)
        {
            Debug.LogError("Required components missing!");
        }

        // Initialize UI
        UpdateUI();
        gameOverUI.SetActive(false);
        winUI.SetActive(false);
    }

    void Update()
    {
        if (isGameOver || hasWon) return;

        // ----- Movement -----
        float horizontal = Input.GetAxis("Horizontal");

        // Move
        Vector2 velocity = rb.velocity;
        velocity.x = horizontal * moveSpeed;
        rb.velocity = velocity;

        // Flip sprite
        if (horizontal != 0)
        {
            Vector3 scale = transform.localScale;
            scale.x = Mathf.Sign(horizontal) * Mathf.Abs(scale.x);
            transform.localScale = scale;
        }

        // Set animation speed
        animator.SetFloat("Speed", Mathf.Abs(horizontal));

        // ----- Jump -----
        if (Input.GetButtonDown("Jump") && isGrounded)
        {
            rb.AddForce(Vector2.up * jumpForce, ForceMode2D.Impulse);
            animator.SetTrigger("Jump");
            isGrounded = false;
            animator.SetBool("Grounded", false);
        }

        // ----- Attack -----
        if (Input.GetButtonDown("Fire1"))
        {
            animator.SetTrigger("Attack");
        }

        // ----- Debug: Take damage with key -----
        if (Input.GetKeyDown(KeyCode.H))
        {
            TakeDamage(10);
        }

        // ----- Debug: Heal with key -----
        if (Input.GetKeyDown(KeyCode.L))
        {
            Heal(10);
        }
    }

    void OnCollisionEnter2D(Collision2D collision)
    {
        if (collision.gameObject.CompareTag("Ground"))
        {
            isGrounded = true;
            animator.SetBool("Grounded", true);
        }

        // ----- Collectibles -----
        if (collision.gameObject.CompareTag("Coin"))
        {
            AddScore(10);
            coinCount++;
            Destroy(collision.gameObject);
            Debug.Log("Coin collected!");
        }

        if (collision.gameObject.CompareTag("HealthPotion"))
        {
            Heal(25);
            Destroy(collision.gameObject);
            Debug.Log("Health potion collected!");
        }

        // ----- Enemies -----
        if (collision.gameObject.CompareTag("Enemy"))
        {
            // Check if we're stomping the enemy
            if (transform.position.y > collision.transform.position.y + 0.5f)
            {
                AddScore(25);
                Destroy(collision.gameObject);
                rb.AddForce(Vector2.up * 5f, ForceMode2D.Impulse);
                Debug.Log("Enemy stomped!");
            }
            else
            {
                TakeDamage(20);
            }
        }

        // ----- Win Condition -----
        if (collision.gameObject.CompareTag("Goal"))
        {
            WinGame();
        }

        // ----- Death (falling) -----
        if (collision.gameObject.CompareTag("DeathZone"))
        {
            TakeDamage(100);
        }
    }

    public void TakeDamage(int damage)
    {
        currentHealth -= damage;
        if (currentHealth < 0) currentHealth = 0;
        UpdateUI();

        animator.SetTrigger("Hit");

        if (currentHealth <= 0)
        {
            GameOver();
        }
    }

    public void Heal(int amount)
    {
        currentHealth += amount;
        if (currentHealth > maxHealth) currentHealth = maxHealth;
        UpdateUI();
    }

    public void AddScore(int points)
    {
        score += points;
        UpdateUI();
    }

    void UpdateUI()
    {
        if (scoreText != null)
        {
            scoreText.text = "Score: " + score;
        }

        if (coinText != null)
        {
            coinText.text = "Coins: " + coinCount;
        }

        if (healthBar != null)
        {
            healthBar.fillAmount = (float)currentHealth / maxHealth;

            if (currentHealth > 50)
            {
                healthBar.color = Color.green;
            }
            else if (currentHealth > 25)
            {
                healthBar.color = Color.yellow;
            }
            else
            {
                healthBar.color = Color.red;
            }
        }
    }

    void GameOver()
    {
        isGameOver = true;
        gameOverUI.SetActive(true);
        Time.timeScale = 0f;
        Debug.Log("Game Over! Score: " + score);
    }

    void WinGame()
    {
        hasWon = true;
        winUI.SetActive(true);
        Time.timeScale = 0f;
        Debug.Log("You Win! Score: " + score);
    }

    public void RestartGame()
    {
        Time.timeScale = 1f;
        SceneManager.LoadScene(SceneManager.GetActiveScene().name);
    }

    public void QuitGame()
    {
        Application.Quit();
    }
}

